const ICON_TYPES = [
  { value: 'solid', label: 'Solid', prefix: 'fas' },
  { value: 'regular', label: 'Regular', prefix: 'far' },
  { value: 'light', label: 'Light', prefix: 'fal' },
  { value: 'thin', label: 'Thin', prefix: 'fat' },
  { value: 'duotone', label: 'Duotone', prefix: 'fad' },
  { value: 'brands', label: 'Brands', prefix: 'fab' }
] as const;

